local lazypath = vim.fn.stdpath("data") .. "/lazy/lazy.nvim"

if not vim.uv.fs_stat(lazypath) then
    vim.fn.system({
        "git",
        "clone",
        "--filter=blob:none",
        "https://github.com/folke/lazy.nvim.git",
        "--branch=stable", -- latest stable release
        lazypath,
    })
end

vim.opt.rtp:prepend(lazypath)

require("config")
require("options")
require("lib")
require("keymaps")
require("autocmd")
require("lsp-config")

require("lazy").setup("specs", {
    defaults = {
        lazy = true,
    },
    performance = {
        rtp = {
            disabled_plugins = {
                "gzip",
                "netrwPlugin",
                "rplugin",
                "tarPlugin",
                "tohtml",
                "tutor",
                "zipPlugin",
            },
        },
    },
    checker = {
        enabled = true,
        notify = false,
    },
    rocks = {
        enabled = false,
    },
    change_detection = {
        notify = false,
    },
    ui = {
        size = { width = 0.8, height = 0.8 },
        border = "solid",
    },
})

local M = {}

---@class VinConfig
M.config = {
    ---@type BlackAtom.Theme.Key
    colorscheme = "black-atom-mnml-orange-light",
    dev_mode = true,
    date_format = "%Y.%m.%d - %A",
    pathes = {
        repos = vim.fn.expand("~/repos"),
        config = {
            nvim = vim.fn.expand("$XDG_CONFIG_HOME") .. "/nvim/lua/config.lua",
            wezterm = vim.fn.expand("$XDG_CONFIG_HOME") .. "/wezterm",
            ghostty = vim.fn.expand("$XDG_CONFIG_HOME") .. "/ghostty",
        },
        notes = {
            personal = vim.fn.expand("~/repos") .. "/nikbrunner/notes",
            the_black_atom = vim.fn.expand("~/repos") .. "/nikbrunner/the-black-atom",
            work = {
                dcd = vim.fn.expand("~/repos") .. "/nikbrunner/dcd-notes",
            },
        },
    },
}

return M.config

