vim.api.nvim_create_autocmd("CmdlineEnter", {
    pattern = ":",
    group = vim.api.nvim_create_augroup("findfunc", { clear = true }),
    callback = function()
        files_cache = {}
    end,
})

edits.newText:
vim.api.nvim_create_autocmd("CmdlineEnter", {
    pattern = ":",
    group = vim.api.nvim_create_augroup("findfunc", { clear = true }),
    callback = function()
        files_cache = {}
    end,
})

-- Also clear cache on directory change to avoid stale file listings
vim.api.nvim_create_autocmd("DirChanged", {
    group = "findfunc",
    callback = function()
        files_cache = {}
    end,
})
